/**
 * Test scaffold emitter — consumes NodeMap directly.
 * Generates per-kind tests: factory produces correct type, render returns non-empty.
 */

import type { NodeMap, AssembledNode, AssembledField } from '../compiler/rule.ts'
import { nameNode } from '../compiler/assemble.ts'

export interface EmitTestsFromNodeMapConfig {
    grammar: string
    nodeMap: NodeMap
}

export function emitTestsFromNodeMap(config: EmitTestsFromNodeMapConfig): string {
    const { grammar, nodeMap } = config

    const lines: string[] = [
        '// Auto-generated by @sittir/codegen — do not edit',
        "import { describe, it, expect } from 'vitest';",
        "import { ir } from '../src/ir.js';",
        '',
    ]

    // Branch/container/polymorph tests
    for (const [kind, node] of nodeMap.nodes) {
        if (!node.factoryName) continue

        switch (node.modelType) {
            case 'branch':
                emitBranchTest(lines, node, kind)
                break
            case 'container':
                emitContainerTest(lines, node, kind)
                break
            case 'polymorph':
                emitPolymorphTest(lines, node, kind)
                break
            case 'leaf':
                emitLeafTest(lines, node, kind)
                break
            case 'keyword':
                emitKeywordTest(lines, node, kind)
                break
            case 'enum':
                emitEnumTest(lines, node, kind)
                break
        }
    }

    return lines.join('\n')
}

function irKey(kind: string): string {
    const { irKey } = nameNode(kind)
    return irKey
}

function emitBranchTest(lines: string[], node: AssembledNode, kind: string): void {
    if (node.modelType !== 'branch') return
    const key = irKey(kind)

    lines.push(`describe('${kind}', () => {`)
    lines.push(`  it('factory produces correct type', () => {`)

    // Build minimal config
    const configParts: string[] = []
    for (const f of node.fields) {
        if (f.required) {
            configParts.push(`${f.propertyName}: ${dummyValue(f)}`)
        }
    }

    const configArg = configParts.length > 0 ? `{ ${configParts.join(', ')} }` : '{}'
    lines.push(`    const node = ir.${key}(${configArg});`)
    lines.push(`    expect(node.type).toBe('${kind}');`)
    lines.push('  });')

    lines.push(`  it('render produces non-empty string', () => {`)
    lines.push(`    const node = ir.${key}(${configArg});`)
    lines.push(`    expect(node.render().length).toBeGreaterThan(0);`)
    lines.push('  });')

    lines.push('});')
    lines.push('')
}

function emitContainerTest(lines: string[], node: AssembledNode, kind: string): void {
    const key = irKey(kind)

    lines.push(`describe('${kind}', () => {`)
    lines.push(`  it('factory produces correct type', () => {`)
    lines.push(`    const node = ir.${key}();`)
    lines.push(`    expect(node.type).toBe('${kind}');`)
    lines.push('  });')
    lines.push('});')
    lines.push('')
}

function emitPolymorphTest(lines: string[], node: AssembledNode, kind: string): void {
    if (node.modelType !== 'polymorph') return
    const key = irKey(kind)

    lines.push(`describe('${kind}', () => {`)
    for (const form of node.forms) {
        lines.push(`  it('${form.name} form produces correct type', () => {`)
        const configParts = form.fields
            .filter(f => f.required)
            .map(f => `${f.propertyName}: ${dummyValue(f)}`)
        const configArg = configParts.length > 0 ? `{ ${configParts.join(', ')} }` : '{}'
        lines.push(`    const node = ir.${key}.${form.name}(${configArg});`)
        lines.push(`    expect(node.type).toBe('${kind}');`)
        lines.push('  });')
    }
    lines.push('});')
    lines.push('')
}

function emitLeafTest(lines: string[], node: AssembledNode, kind: string): void {
    const key = irKey(kind)
    lines.push(`describe('${kind}', () => {`)
    lines.push(`  it('factory produces correct type', () => {`)
    lines.push(`    const node = ir.${key}('test');`)
    lines.push(`    expect(node.type).toBe('${kind}');`)
    lines.push(`    expect(node.text).toBe('test');`)
    lines.push('  });')
    lines.push('});')
    lines.push('')
}

function emitKeywordTest(lines: string[], node: AssembledNode, kind: string): void {
    if (node.modelType !== 'keyword') return
    const key = irKey(kind)
    lines.push(`describe('${kind}', () => {`)
    lines.push(`  it('factory produces keyword', () => {`)
    lines.push(`    const node = ir.${key}();`)
    lines.push(`    expect(node.type).toBe('${kind}');`)
    lines.push(`    expect(node.text).toBe('${node.text}');`)
    lines.push('  });')
    lines.push('});')
    lines.push('')
}

function emitEnumTest(lines: string[], node: AssembledNode, kind: string): void {
    if (node.modelType !== 'enum') return
    const key = irKey(kind)
    const first = node.values[0]
    if (!first) return
    lines.push(`describe('${kind}', () => {`)
    lines.push(`  it('factory accepts valid value', () => {`)
    lines.push(`    const node = ir.${key}('${first.replace(/'/g, "\\'")}');`)
    lines.push(`    expect(node.type).toBe('${kind}');`)
    lines.push('  });')
    lines.push('});')
    lines.push('')
}

function dummyValue(field: AssembledField): string {
    if (field.multiple) return '[]'
    if (field.contentTypes.length > 0) {
        // Use first content type to generate a dummy
        return `{ type: '${field.contentTypes[0]}', text: 'test' } as any`
    }
    return "'test' as any"
}
